export declare const SYNC_STATEMENTS: readonly ["CREATE TABLE IF NOT EXISTS vfs_manifests (\n    hash      BLOB    PRIMARY KEY,\n    size      INTEGER NOT NULL,\n    encoded   BLOB    NOT NULL,\n    last_seen INTEGER NOT NULL DEFAULT 0\n  )", "CREATE TABLE IF NOT EXISTS vfs_changes (\n    id   INTEGER PRIMARY KEY AUTOINCREMENT,\n    rev  INTEGER NOT NULL,\n    path TEXT    NOT NULL,\n    op   TEXT    NOT NULL CHECK(op IN ('delete'))\n  )", "CREATE INDEX IF NOT EXISTS vfs_changes_by_rev ON vfs_changes(rev)", "CREATE INDEX IF NOT EXISTS vfs_changes_by_path ON vfs_changes(path, id DESC)", "CREATE TABLE IF NOT EXISTS _vfs_watermark (\n    k       TEXT    NOT NULL,\n    backend TEXT    NOT NULL DEFAULT 'default',\n    v       INTEGER NOT NULL,\n    PRIMARY KEY (k, backend)\n  )", "CREATE TABLE IF NOT EXISTS _vfs_fetch_cursor (\n    k       TEXT    NOT NULL CHECK(k = 'fetch'),\n    backend TEXT    NOT NULL DEFAULT 'default',\n    path    TEXT,\n    PRIMARY KEY (k, backend)\n  )", "CREATE TABLE IF NOT EXISTS _vfs_mounts (\n    root    TEXT PRIMARY KEY,\n    kind    TEXT NOT NULL,\n    indexed INTEGER NOT NULL DEFAULT 0,\n    mode    TEXT NOT NULL DEFAULT 'read-only'\n            CHECK(mode IN ('read-only', 'read-write'))\n  )"];
